import React, { Component } from 'react';
import Spinner from 'react-bootstrap/Spinner';

export class FetchData extends Component {
  static displayName = FetchData.name;

  constructor(props) {
    super(props);
    this.state = { documents: [], loading: true };
  }

  componentDidMount() {
    this.populateWeatherData();
  }

  static renderForecastsTable(documents) {
    return (
      <table className='table table-striped' aria-labelledby="tabelLabel">
        <thead>
          <tr>
            <th>contents</th>
            <th>Temp. (C)</th>
            <th>Temp. (F)</th>
            <th>Summary</th>
          </tr>
        </thead>
        <tbody>
          {documents.map(document =>
            <tr key={document.datetime}>
              <td>{document.title}</td>
              <td>{document.url}</td>
              <td>{document.datetime}</td>
              <td>{document.contents}</td>
            </tr>
          )}
        </tbody>
      </table>
    );
  }

  render() {
    let contents = this.state.loading
      ? <div>
        <Spinner animation="border" role="status">
          <span className="sr-only">Loading...</span>
        </Spinner>    
      </div>
      : FetchData.renderForecastsTable(this.state.documents);

    return (
      <div>
        <h1 id="tabelLabel" >Weather forecast</h1>
        <p>This component demonstrates fetching data from the server.</p>
        {contents}
      </div>
    );
  }

  async populateWeatherData() {
    const response = await fetch('/api/kakao/daumSearch/web?query=test');
    const data = await response.json();
    this.setState({ documents: data, loading: false });
  }
}
